{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/Issue2535Test.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

/**
 * Test for issue #2535: Missing whitespace before function body is inserted in wrong place in AST.
 *
 * The issue was that when multiple rules tried to insert whitespace before a function body block,
 * the whitespace element was inserted in the wrong position in the AST, causing ktlint to report
 * that not all violations could be resolved in 3 consecutive runs of format.
 */
class Issue2535Test {
    private val functionSignatureRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Test
    fun `Issue 2535 - Given a function without space before body block in class then format correctly in single run`() {
        val code =
            """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player){
                    notificationManager.setPlayer(player)
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player) {
                    notificationManager.setPlayer(player)
                }
            }
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .addAdditionalRuleProvider { FunctionStartOfBodySpacingRule() }
            .addAdditionalRuleProvider { SpacingAroundCurlyRule() }
            .hasLintViolation(6, 50, "Expected a single space before body block")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue 2535 - Given a simple function without space before body block then format correctly`() {
        val code =
            """
            fun foo(){
                bar()
            }
            """.trimIndent()
        val formattedCode =
            """
            fun foo() {
                bar()
            }
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .addAdditionalRuleProvider { FunctionStartOfBodySpacingRule() }
            .addAdditionalRuleProvider { SpacingAroundCurlyRule() }
            .hasLintViolation(1, 9, "Expected a single space before body block")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue 2535 - Given a function with parameters and no space before body block then format correctly`() {
        val code =
            """
            fun calculate(a: Int, b: Int){
                return a + b
            }
            """.trimIndent()
        val formattedCode =
            """
            fun calculate(a: Int, b: Int) {
                return a + b
            }
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .addAdditionalRuleProvider { FunctionStartOfBodySpacingRule() }
            .addAdditionalRuleProvider { SpacingAroundCurlyRule() }
            .hasLintViolation(1, 30, "Expected a single space before body block")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue 2535 - Given a function with return type and no space before body block then format correctly`() {
        val code =
            """
            fun calculate(a: Int, b: Int): Int{
                return a + b
            }
            """.trimIndent()
        val formattedCode =
            """
            fun calculate(a: Int, b: Int): Int {
                return a + b
            }
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .addAdditionalRuleProvider { FunctionStartOfBodySpacingRule() }
            .addAdditionalRuleProvider { SpacingAroundCurlyRule() }
            .hasLintViolation(1, 35, "Expected a single space before body block")
            .isFormattedAs(formattedCode)
    }
}
"}

