375→ * leaf node in this [CompositeElement]. In case [to] is a [CompositeElement] than the last node in the sequence is the last leaf node of
376→ * this [CompositeElement].
377→ */
378→public fun leavesInClosedRange(
379→    from: ASTNode,
380→    to: ASTNode,
381→): Sequence<ASTNode> {
382→    val stopAtLeaf =
383→        to
384→            .lastChildLeafOrSelf()
385→            .nextLeaf()
386→    return from
387→        .firstChildLeafOrSelf()
388→        .leavesIncludingSelf()
389→        .takeWhile { it != stopAtLeaf }
390→}
