/**
 * Test for issue #2535: Missing whitespace before function body is inserted in wrong place in AST.
 *
 * The issue was that when multiple rules tried to insert whitespace before a function body block,
 * the whitespace element was inserted in the wrong position in the AST, causing ktlint to report
 * that not all violations could be resolved in 3 consecutive runs of format.
 */
class Issue2535Test {
    private val functionSignatureRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Test
    fun `Issue 2535 - Given a function without space before body block in class then format correctly in single run`() {
        val code =
            """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player){
                    notificationManager.setPlayer(player)
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player) {
                    notificationManager.setPlayer(player)
                }
            }
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .addAdditionalRuleProvider { FunctionStartOfBodySpacingRule() }
            .addAdditionalRuleProvider { SpacingAroundCurlyRule() }
            .hasLintViolation(6, 50, "Expected a single space before body block")
            .isFormattedAs(formattedCode)
    }

